if (Test-Path -LiteralPath $oldSvgFavicon) {
  Remove-Item -LiteralPath $oldSvgFavicon -Force
}

$logoSource = Join-Path $WebAppPath 'src/assets/tredstone-logo.png'
$faviconTarget = Join-Path $WebAppPath 'public/favicon.png'
$fallbackFaviconBase64 = ''

function Write-FallbackFavicon {
  param([string]$Reason)
  New-Item -ItemType Directory -Force -Path (Split-Path -Parent $faviconTarget) | Out-Null
  [System.IO.File]::WriteAllBytes($faviconTarget, [Convert]::FromBase64String($fallbackFaviconBase64))
  Write-Warning "$Reason Fallback favicon was written to $faviconTarget."
}

function Test-ReadablePng {
  param([string]$Path)
  if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) { return $false }
  try {
    $stream = [System.IO.File]::Open($Path, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
    try {
      $signature = New-Object byte[] 8
      $read = $stream.Read($signature, 0, 8)
      if ($read -ne 8) { return $false }
      $pngSignature = [byte[]](137, 80, 78, 71, 13, 10, 26, 10)
      for ($i = 0; $i -lt 8; $i++) {
        if ($signature[$i] -ne $pngSignature[$i]) { return $false }
      }
      return $true
    } finally {
      $stream.Dispose()
    }
  } catch {
    return $false
  }
}

if (-not (Test-ReadablePng -Path $logoSource)) {
  Write-FallbackFavicon "Logo source missing or invalid: $logoSource."
} else {
  try {
    Add-Type -AssemblyName System.Drawing -ErrorAction Stop
    $logoImage = $null
    $canvas = $null
    $graphics = $null
    try {
      $logoImage = [System.Drawing.Image]::FromFile($logoSource)
      if (($logoImage.Width -le 0) -or ($logoImage.Height -le 0)) {
        throw "Logo image has invalid dimensions: $($logoImage.Width)x$($logoImage.Height)."
      }
      New-Item -ItemType Directory -Force -Path (Split-Path -Parent $faviconTarget) | Out-Null
      $canvas = New-Object System.Drawing.Bitmap 64, 64, ([System.Drawing.Imaging.PixelFormat]::Format32bppArgb)
      $graphics = [System.Drawing.Graphics]::FromImage($canvas)
      $graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality
      $graphics.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic
      $graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::HighQuality
      $graphics.Clear([System.Drawing.Color]::Transparent)
      $maxSide = 64
      $scale = [Math]::Min($maxSide / $logoImage.Width, $maxSide / $logoImage.Height)
      $drawWidth = [Math]::Max(1, [int]($logoImage.Width * $scale))
      $drawHeight = [Math]::Max(1, [int]($logoImage.Height * $scale))
      $drawX = [int]((64 - $drawWidth) / 2)
      $drawY = [int]((64 - $drawHeight) / 2)
      $graphics.DrawImage($logoImage, $drawX, $drawY, $drawWidth, $drawHeight)
      $canvas.Save($faviconTarget, [System.Drawing.Imaging.ImageFormat]::Png)
    } finally {
      if ($graphics -ne $null) { $graphics.Dispose() }
      if ($canvas -ne $null) { $canvas.Dispose() }
      if ($logoImage -ne $null) { $logoImage.Dispose() }
    }
  } catch {
    Write-FallbackFavicon "Unable to read or resize logo image: $($_.Exception.Message)."
  }
}


$assetPngPaths = @(
  'src/assets/created-showcase/portrait-premium.png',
  'src/assets/created-showcase/brand-ad.png',
  'src/assets/created-showcase/voice-card.png',
  'src/assets/created-showcase/scenario-card.png',
  'src/assets/created-showcase/music-card.png',
  'src/assets/hero-previews/watermark-preview.png',
  'src/assets/hero-previews/photoshoot-preview.png',
  'src/assets/hero-previews/brand-preview.png',
  'src/assets/hero-previews/reels-preview.png'
)
foreach ($assetPngPath in $assetPngPaths) {
  $assetTarget = Join-Path $WebAppPath $assetPngPath
  New-Item -ItemType Directory -Force -Path (Split-Path -Parent $assetTarget) | Out-Null
  [System.IO.File]::WriteAllBytes($assetTarget, [Convert]::FromBase64String($fallbackFaviconBase64))
}
$reelsVideoTarget = Join-Path $WebAppPath 'src/assets/created-showcase/reels-video.mp4'
$reelsVideoBase64 = ''
New-Item -ItemType Directory -Force -Path (Split-Path -Parent $reelsVideoTarget) | Out-Null
[System.IO.File]::WriteAllBytes($reelsVideoTarget, [Convert]::FromBase64String($reelsVideoBase64))


npm install
npm run dev
